import React from "react";
import FeatureDetail from "./FeatureDetail";

const pageData = {
  title: "Cloud Security Audits",
  subtitle: "Automated comprehensive cloud infrastructure security checks",
  description: "Automate your cloud security posture management with comprehensive audits. Check S3 buckets, IAM roles, KMS encryption, VPC configurations, and more across AWS, Azure, and GCP environments. Get actionable insights and remediation guidance.",
  benefits: [
    "Automated S3 bucket permission and configuration checks",
    "IAM role and policy security analysis",
    "KMS encryption status verification",
    "CloudTrail logging configuration verification",
    "Multi-cloud support for AWS, Azure, and GCP"
  ],
  features: [
    { title: "Multi-Cloud Support", description: "Support for AWS, Azure, GCP, and Kubernetes" },
    { title: "500+ Security Checks", description: "Comprehensive coverage of cloud security best practices" },
    { title: "Continuous Monitoring", description: "Real-time detection of configuration drift" },
    { title: "Remediation Guides", description: "Step-by-step instructions for fixing issues" },
    { title: "Compliance Mapping", description: "Map findings to compliance frameworks" }
  ],
  howItWorks: [
    { title: "Cloud Connection", description: "Connect to your cloud accounts securely via read-only APIs" },
    { title: "Scanning", description: "Automated scanning of all cloud resources and configurations" },
    { title: "Analysis", description: "Findings are analyzed against security best practices" },
    { title: "Reporting", description: "Comprehensive reports with remediation guidance are generated" }
  ],
  color: "#0ea5e9",
  icon: "M3 10h18M7 15h1m4 0h1m-7 4h12a3 3 0 003-3V8a3 3 0 00-3-3H6a3 3 0 00-3 3v8a3 3 0 003 3z",
  gradient: "from-sky-500 to-blue-600"
};

function CloudAudits() {
  return <FeatureDetail {...pageData} />;
}

export default CloudAudits;
